  ('social-worker-moex-05407', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作在各個災難階段，均有主要的任務目標，請問在讓受災民眾可以身心安頓、檢視損傷及整備重 建，係屬於下列何種階段？', '["緊急救援與安置階段", "中繼期安置階段", "後期重建階段", "長期復健階段"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05408', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '請問下列何者並非屬於女性照顧者之減壓服務項目？', '["托兒托老照顧服務", "成長團體", "多元保護網絡", "親子成長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
